import React, { useState, useContext } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import { AuthContext } from '../context/AuthContext';
import '../styles/auth.css';

const Login = () => {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const { login } = useContext(AuthContext);
  const navigate = useNavigate();

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      const res = await fetch('/api/auth/login', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ email, password })
      });
      const data = await res.json();
      if (res.ok) {
        login(data);
        navigate('/');
      } else {
        alert(data.message);
      }
    } catch (error) {
      console.error(error);
    }
  };

  const performLogin = async (emailVal, passwordVal) => {
    try {
      const res = await fetch('/api/auth/login', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ email: emailVal, password: passwordVal })
      });
      const data = await res.json();
      if (res.ok) {
        login(data);
        navigate('/');
      } else {
        alert(data.message);
      }
    } catch (error) {
      console.error(error);
    }
  };

  const requestAdminSecretAndLogin = () => {
    const ADMIN_SECRET = process.env.REACT_APP_ADMIN_SECRET || 'ADMINCODE123';
    const secret = window.prompt('Enter admin secret code:');
    if (!secret) return;
    if (secret !== ADMIN_SECRET) {
      alert('Incorrect admin secret');
      return;
    }
    performLogin('admin@shopnest.com', 'password123');
  };

  return (
    <div className="auth-container">
      <form onSubmit={handleSubmit} className="auth-form">
        <h2>Login</h2>
        <input type="email" placeholder="Email" value={email} onChange={(e) => setEmail(e.target.value)} required />
        <input type="password" placeholder="Password" value={password} onChange={(e) => setPassword(e.target.value)} required />
        <div style={{ display: 'flex', gap: '8px', width: '100%' }}>
          <button type="submit" className="btn" style={{ flex: 1 }}>Login</button>
          <button type="button" className="btn" style={{ flex: 1, background: '#f97316' }} onClick={requestAdminSecretAndLogin}>Login as Admin</button>
        </div>
        <p>Don't have an account? <Link to="/register">Register</Link></p>
      </form>
    </div>
  );
};

export default Login;
